{"type":"user","message":{"role":"user","content":[{"tool_use_id":"tooluse_OqCDDCeyX6FiE4w4Zq3Fnx","type":"tool_result","content":"1\t#!/usr/bin/env python3\n2\t\"\"\"\n3\t识别创业板\"地量之后天量\"突破形态\n4\t截止日期：2024-06-07\n5\t\"\"\"\n6\t\n7\timport akshare as ak\n8\timport pandas as pd\n9\tfrom datetime import datetime, timedelta\n10\timport warnings\n11\twarnings.filterwarnings('ignore')\n12\t\n13\tdef get_chinext_stocks():\n14\t    \"\"\"获取创业板股票列表\"\"\"\n15\t    try:\n16\t        stock_info = ak.stock_info_a_code_name()\n17\t        # 创业板代码以300开头\n18\t        chinext = stock_info[stock_info['code'].str.startswith('300')]\n19\t        return chinext['code'].tolist()\n20\t    except:\n21\t        # 备用方案：手动构建部分创业板代码\n22\t        return [f\"300{str(i).zfill(3)}\" for i in range(1, 1000)]\n23\t\n24\tdef get_stock_data(code, end_date='2024-06-07'):\n25\t    \"\"\"获取股票历史数据\"\"\"\n26\t    try:\n27\t        # 获取前90天数据以确保有足够的60日均量计算\n28\t        start_date = (datetime.strptime(end_date, '%Y-%m-%d') - timedelta(days=120)).strftime('%Y-%m-%d')\n29\t        df = ak.stock_zh_a_hist(symbol=code, period=\"daily\", start_date=start_date, end_date=end_date, adjust=\"qfq\")\n30\t        if df is None or len(df) < 60:\n31\t            return None\n32\t\n33\t        # 标准化列名\n34\t        df.rename(columns={\n35\t            '日期': 'date',\n36\t            '开盘': 'open',\n37\t            '收盘': 'close',\n38\t            '最高': 'high',\n39\t            '最低': 'low',\n40\t            '成交量': 'volume'\n41\t        }, inplace=True)\n42\t\n43\t        df['date'] = pd.to_datetime(df['date'])\n44\t        df = df.sort_values('date').reset_index(drop=True)\n45\t        return df\n46\t    except Exception as e:\n47\t        return None\n48\t\n49\tdef calculate_60day_avg_volume(df, idx):\n50\t    \"\"\"计算60日均量\"\"\"\n51\t    if idx < 59:\n52\t        return None\n53\t    return df.iloc[idx-59:idx+1]['volume'].mean()\n54\t\n55\tdef find_doji_periods(df, end_idx, lookback=30):\n56\t    \"\"\"\n57\t    在截止日期前30日内查找地量期\n58\t    地量期：连续≥3天，每天成交量 < 60日均量的50%\n59\t    横盘整理：地量期内价格波动 < 3%\n60\t    \"\"\"\n61\t    doji_periods = []\n62\t\n63\t    start_idx = max(59, end_idx - lookback + 1)  # 确保有60日数据\n64\t\n65\t    i = start_idx\n66\t    while i <= end_idx:\n67\t        avg_vol_60 = calculate_60day_avg_volume(df, i)\n68\t        if avg_vol_60 is None:\n69\t            i += 1\n70\t            continue\n71\t\n72\t        # 检查是否为地量日\n73\t        if df.iloc[i]['volume'] < avg_vol_60 * 0.5:\n74\t            # 找连续地量期\n75\t            period_start = i\n76\t            period_end = i\n77\t\n78\t            while period_end < end_idx:\n79\t                next_idx = period_end + 1\n80\t                next_avg_vol = calculate_60day_avg_volume(df, next_idx)\n81\t                if next_avg_vol and df.iloc[next_idx]['volume'] < next_avg_vol * 0.5:\n82\t                    period_end = next_idx\n83\t                else:\n84\t                    break\n85\t\n86\t            # 地量期至少3天\n87\t            period_days = period_end - period_start + 1\n88\t            if period_days >= 3:\n89\t                # 检查横盘条件：价格波动 < 3%\n90\t                period_data = df.iloc[period_start:period_end+1]\n91\t                high_price = period_data['high'].max()\n92\t                low_price = period_data['low'].min()\n93\t\n94\t                if low_price > 0:\n95\t                    price_range = (high_price - low_price) / low_price\n96\t\n97\t                    if price_range < 0.03:  # 横盘条件：振幅 < 3%\n98\t                        doji_periods.append({\n99\t                            'start_idx': period_start,\n100\t                            'end_idx': period_end,\n101\t                            'days': period_days,\n102\t                            'price_range': price_range\n103\t                        })\n104\t\n105\t            i = period_end + 1\n106\t        else:\n107\t            i += 1\n108\t\n109\t    return doji_periods\n110\t\n111\tdef check_surge_breakout(df, doji_period):\n112\t    \"\