{"type":"user","message":{"role":"user","content":[{"tool_use_id":"tooluse_H9VF32WOAJOdof5Yaef4TQ","type":"tool_result","content":"#!/usr/bin/env python3\n\"\"\"\n识别创业板\"地量之后天量\"突破形态\n截止日期: 2024-06-07\n\"\"\"\n\nimport akshare as ak\nimport pandas as pd\nimport numpy as np\nfrom datetime import datetime, timedelta\nimport warnings\nwarnings.filterwarnings('ignore')\n\ndef get_chinext_stocks():\n    \"\"\"获取创业板股票列表\"\"\"\n    try:\n        stock_info = ak.stock_info_a_code_name()\n        chinext = stock_info[stock_info['code'].str.startswith('300')]\n        return chinext['code'].tolist()\n    except:\n        return []\n\ndef get_stock_data(code, end_date='2024-06-07'):\n    \"\"\"获取股票历史数据，需要至少90天数据（60日均量+30日检测窗口）\"\"\"\n    try:\n        # 获取更长时间的数据以计算60日均量\n        start_date = (datetime.strptime(end_date, '%Y-%m-%d') - timedelta(days=150)).strftime('%Y%m%d')\n        end_date_fmt = datetime.strptime(end_date, '%Y-%m-%d').strftime('%Y%m%d')\n        \n        df = ak.stock_zh_a_hist(symbol=code, period=\"daily\", \n                                start_date=start_date, end_date=end_date_fmt, adjust=\"qfq\")\n        \n        if df is None or len(df) < 70:\n            return None\n            \n        df = df.rename(columns={\n            '日期': 'date',\n            '开盘': 'open',\n            '收盘': 'close',\n            '最高': 'high',\n            '最低': 'low',\n            '成交量': 'volume'\n        })\n        \n        df['date'] = pd.to_datetime(df['date'])\n        df = df.sort_values('date').reset_index(drop=True)\n        \n        return df[['date', 'open', 'close', 'high', 'low', 'volume']]\n    except Exception as e:\n        return None\n\ndef calculate_60d_avg_volume(df, idx):\n    \"\"\"计算指定位置的60日平均成交量\"\"\"\n    if idx < 59:\n        return None\n    return df.iloc[idx-59:idx+1]['volume'].mean()\n\ndef find_low_volume_periods(df, end_idx):\n    \"\"\"\n    在end_idx之前的30日内查找连续≥3天的地量期\n    地量定义: 单日成交量 < 60日均量的50%\n    横盘条件: 地量期内(最高价-最低价)/最低价 < 3%\n    \"\"\"\n    low_volume_periods = []\n    \n    # 检测窗口: end_idx之前的30天\n    start_search_idx = max(60, end_idx - 29)  # 至少从第60天开始（需要60日均量）\n    \n    i = start_search_idx\n    while i <= end_idx:\n        avg_vol_60 = calculate_60d_avg_volume(df, i)\n        if avg_vol_60 is None:\n            i += 1\n            continue\n        \n        # 检查是否是地量日\n        if df.iloc[i]['volume'] < avg_vol_60 * 0.5:\n            # 找连续地量期\n            period_start = i\n            period_end = i\n            \n            # 向后扩展连续地量日\n            j = i + 1\n            while j <= end_idx:\n                avg_vol_j = calculate_60d_avg_volume(df, j)\n                if avg_vol_j and df.iloc[j]['volume'] < avg_vol_j * 0.5:\n                    period_end = j\n                    j += 1\n                else:\n                    break\n            \n            # 检查连续天数是否≥3\n            period_days = period_end - period_start + 1\n            if period_days >= 3:\n                # 检查横盘条件: 地量期内价格波动<3%\n                period_data = df.iloc[period_start:period_end+1]\n                high_max = period_data['high'].max()\n                low_min = period_data['low'].min()\n                price_range_pct = (high_max - low_min) / low_min * 100","is_error":false}]},"parent_tool_use_id":null,"session_id":"6b338d3c-6e3b-4a7d-846e-b817def70b38","uuid":"13264267-e4a6-4ab1-b56d-07268a97924f","timestamp":"2026-04-16T00:30:47.013Z","tool_use_result":{"stdout":"#!/usr/bin/env python3\n\"\"\"\n识别创业板\"地量之后天量\"突破形态\n截止日期: 2024-06-07\n\"\"\"\n\nimport akshare as ak\nimport pandas as pd\nimport numpy as np\nfrom datetime import datetime, timedelta\nimport warnings\nwarnings.filterwarnings('ignore')\n\ndef get_chinext_stocks():\n    \"\"\"获取创业板股票列表\"\"\"\n    try:\n        stock_info = ak.stock_info_a_code_name()\n        chinext = stock_info[stock_info['code'].str.startswith('300')]\n        return chinext['code'].tolist()\n    except:\n        return []\n\ndef get_stock_data(code, end_date='2024-06-0